css:
.loader {
  color: var(--loader-color, #6366f1);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
width: 15px;
aspect-ratio: 1;
border-radius: 50%;
animation: l5 1s infinite linear alternate;
}
@keyframes l5 {
0% {box-shadow: 20px 0 currentColor, -20px 0 #0002;background: currentColor }
33% {box-shadow: 20px 0 currentColor, -20px 0 #0002;background: #0002}
66% {box-shadow: 20px 0 #0002,-20px 0 currentColor; background: #0002}
100%{box-shadow: 20px 0 #0002,-20px 0 currentColor; background: currentColor }
}
